-- =====================================================
-- Migration 005: Module 7.4 - The Path to True Intimacy
-- 1 parent lesson + 4 child sub-lessons
-- All is_preview = true (Module 7 is free preview)
-- Run this in Supabase SQL Editor AFTER 004_add_parent_lesson.sql
-- =====================================================

DO $$
DECLARE
  mod7_id uuid;
  parent_id uuid;
BEGIN
  SELECT id INTO mod7_id FROM modules WHERE module_number = '7';

  -- Parent lesson: The Path to True Intimacy (hub/intro page)
  INSERT INTO lessons (module_id, title, sort_order, is_preview, content_json)
  VALUES (mod7_id, 'The Path to True Intimacy', 4, true, '{"estimated_minutes": 8, "blocks": [{"type": "heading", "content": "Healing Hearts and Rekindled Flames: The Path to True Intimacy"}, {"type": "text", "content": "As we move from Module 7:3: Letting Go to Living Free, we learned to release old hurts, resentments, and patterns that no longer serve us. Now, we step into a space of renewal and deeper connection. Intimacy isn''t just rebuilt; it flourishes when we feel truly seen, safe, and free to be ourselves."}, {"type": "bold_text", "content": "Trisha"}, {"type": "text", "content": "Hi everyone, it''s Trisha. This Healing Hearts program is a curriculum I''ve poured my heart into over the years, and this is the first time I''ve invited someone else to contribute to such an important, sacred module. I feel completely safe asking Jeff, my husband and partner in this journey, to help me write on intimacy. His perspective as a husband and clinician brings powerful, grounded insights that beautifully complement what we''ve built together. I love how he''s captured the clinical essentials so exceptionally well. Now, I''ll add a few personal thoughts and experiences to make it even more real. Jeff gave us the roadmap; I''ll share vulnerability about our path, so you can see where we''ve been, and where hope and healing can take you, too."}, {"type": "text", "content": "We introduced the six levels of intimacy in Module 1:3. Now, in Module 7:4, we build on that foundation with a deeper, more practical exploration, so nurturing every level of intimacy becomes intentional and connected, ultimately allowing sexual intimacy to emerge as the natural, joyful \"cherry on top.\""}, {"type": "text", "content": "Commentary will be highlighted with our names at the top to help identify the author of each section."}, {"type": "subheading", "content": "What You Will Learn in This Module"}, {"type": "text", "content": "In Healing Hearts, Rekindled Flames: The Path to True Intimacy. You will see how intimacy is rebuilt from the inside out, beginning with emotional and physical safety and expanding into sexual connection that feels mutual, joyful, and secure."}, {"type": "text", "content": "You will learn:"}, {"type": "list", "items": ["Six levels of intimacy build the real foundation (emotional and physical safety first; sex as the joyful \"cherry on top\").", "SPARK tool for handling triggers and tough talks with empathy and quick repair.", "Everyday sliding door moments create lasting trust.", "Betrayal trauma''s nervous system impact -- and how consistent safety, patience, and repair restore it.", "Responsive desire: arousal grows from feeling connected, safe, and pursued (common for many women).", "Remove brakes (pressure, pain) and build accelerators (non-demanding touch, emotional safety, intentional planning)."], "ordered": false}, {"type": "text", "content": "Real hope from our story: from pain and distance to secure, rekindled flames. Change is possible. Let''s begin!"}, {"type": "divider"}, {"type": "subheading", "content": "What''s Ahead"}, {"type": "text", "content": "This module is split into four sections, each building on the last. Take your time with each one and discuss together as you go."}, {"type": "list", "items": ["Foundations & Safety -- Trust, commitment, SPARK tool, sliding door moments, and healing betrayal trauma", "The Connection Layers -- Verbal, emotional, and intellectual intimacy", "Spiritual & Physical Intimacy -- Shared meaning, safe touch, and the dual control model", "Sexual Connection & Action Plan -- Altruistic pleasure, sacred connection, and your weekly maintenance plan"], "ordered": true}]}')
  RETURNING id INTO parent_id;

  -- Child 1: Foundations & Safety
  INSERT INTO lessons (module_id, parent_lesson_id, title, sort_order, is_preview, content_json)
  VALUES (mod7_id, parent_id, 'Foundations & Safety', 5, true, '{"estimated_minutes": 35, "blocks": [{"type": "heading", "content": "Foundations & Safety"}, {"type": "bold_text", "content": "Jeff"}, {"type": "text", "content": "When you hear the word, \"intimacy,\" what is your first thought? Most people think sex, physical closeness, and connectedness, probably in that order. All of those definitions are correct, but I think \"sex\" would be the overwhelmingly common first thought."}, {"type": "text", "content": "Steve was a recent client. He and his wife, Jenny, were seeing us for the first time. After discussing their issues for a short time, it was clear that Steve was the higher libido partner, and Jenny, the lower libido partner."}, {"type": "text", "content": "\"Jenny never wants to spend time with me, sexually. She is always tired or has some other excuse. I can''t remember the last time she initiated lovemaking. I don''t know what to do.\""}, {"type": "text", "content": "Jenny discussed, \"Steve is always pestering me for sex. I don''t mind sex, and sometimes it is really fun, but I just feel so much pressure, and if I don''t respond when he wants me to, or how he wants me to, he pouts the rest of the day and won''t talk to me.\""}, {"type": "text", "content": "This scenario happens all too frequently in many couples, and in one way or another, haven''t you felt like Jenny or Steve? Both people are left wanting more, more sex, more closeness, more connection, more intimacy. But how do you get there, where you both feel wanted, loved and connected? You''re in the right place! Sit back and let''s go through this."}, {"type": "text", "content": "The term \"six levels of intimacy\" most commonly refers to a psychological framework used to describe the different ways human beings connect and build closeness. While we discussed these previously, a quick review is important. While many people equate intimacy strictly with physical or sexual contact, experts generally categorize it into six distinct \"buckets\" or areas of life."}, {"type": "subheading", "content": "The Six Levels of Intimacy"}, {"type": "list", "items": ["1. Physical -- Non-sexual touch and proximity. Examples: Holding hands, hugging, sitting close while watching a movie, or a hand on the shoulder.", "2. Emotional -- Sharing your inner world and feelings. Examples: Discussing fears, dreams, and insecurities; feeling safe enough to be vulnerable without judgment.", "3. Intellectual -- Connecting through ideas and beliefs. Examples: Debating a news story, discussing a book, or sharing your philosophy on life and values.", "4. Spiritual -- Sharing a sense of meaning or purpose. Examples: Praying or meditating together, volunteering for a shared cause, or discussing \"big picture\" life questions.", "5. Experiential -- Creating memories through shared activities. Examples: Traveling together, working on a DIY project, or simply running errands as a team.", "6. Creative -- Expressing yourself through shared creation. Examples: Cooking a new meal together, painting, or even brainstorming solutions to a domestic problem."], "ordered": false}, {"type": "text", "content": "Developing a healthy relationship usually involves nurturing all six levels, rather than focusing on just one or two. This module is intended to help you put the ''fun'' in the fundamentals and the \"SPARK\" back into your relationship. When these are good, both individually and together, sex is the natural expression of your two halves becoming one."}, {"type": "divider"}, {"type": "subheading", "content": "Understanding the Progression"}, {"type": "text", "content": "In many therapeutic models, these levels are seen as a foundation. For example, Sexual Intimacy is often considered \"the cherry on top\" or an \"expression\" that flourishes most when the other levels -- especially emotional and physical -- are strong."}, {"type": "text", "content": "Often in Western and other societies, sexuality is considered an ''obligation,'' especially of the wife. If there is anything that kills sexual energy, it''s feeling like you are duty bound to perform sexually. Sexuality is the deepest form of person-to-person communication, and if one of the partners feels pressured or obligated to have sex, frequency will suffer greatly, and connection will almost assuredly be sacrificed."}, {"type": "divider"}, {"type": "bold_text", "content": "Trisha"}, {"type": "text", "content": "I know exactly what that feels like. Like Steve and Jenny, and so many of you, Jeff and I walked through long, hard seasons where physical intimacy felt worlds away. Between the exhaustion of raising little ones, running the house, and Jeff''s grueling physician schedule filled with late nights, missed recitals, and weekend calls, we weren''t a team anymore. We were just two ships passing in the night."}, {"type": "text", "content": "The exhaustion was deep, but what we didn''t understand then were the old survival patterns we were both carrying. Because our childhoods were rough, we didn''t have a map for healthy love or how to fix things after a fight. We only knew how to survive."}, {"type": "text", "content": "Jeff''s fearful-avoidant style meant he was constantly reaching for connection while simultaneously feeling terrified to actually let it in. His mother loved him, but she struggled to provide the emotional safety and consistency he needed. That unpredictability left him unsure how to trust closeness, always longing for connection while also bracing for it to disappear."}, {"type": "text", "content": "I carried a similar fearful-avoidant pattern from my own history of trauma and abuse from my dad. I deeply longed for safety and connection, but it often showed up as fawning. I became the overachieving people-pleaser, working hard to keep everything calm and \"safe,\" often at my own expense, while feeling conflicted and small inside."}, {"type": "text", "content": "In those years, we were like two terrified cats stuck high in a tree, aching to be close, but too frozen to come down. This isn''t about blame. It''s about finally understanding why we did what we did, so we can heal."}, {"type": "text", "content": "As I''ve gone deeper into this journey of learning and healing, I''ve come to realize just how instrumental my mother has been in my life. Despite the abuse she endured herself, she showed me what unconditional love looks like. I''m deeply grateful for my sweet mother, who also became a beautiful part of Jeff''s healing."}, {"type": "text", "content": "No one had taught us how to quiet our nervous systems, probably because they didn''t know, either. As a consequence, we were just two wounded hearts trying to love each other without any tools."}, {"type": "text", "content": "What we finally realized is exactly what Jeff said: chemistry follows connection; it''s built in the tiny, ordinary moments. It''s the soft tone you use after a long day, a gentle touch as you pass in the hallway, or a quiet check-in while you''re at the grocery store. It grows through eye contact, shared laughter, and choosing to show up, over and over again."}, {"type": "callout", "icon": "heart", "content": "Sex isn''t the foundation of intimacy; it''s the celebration of it, the cherry on top. When emotional safety finally has room to grow, physical desire finally has space to breathe."}, {"type": "text", "content": "Through gritty work, forgiveness, and learning to finally feel safe in our own skin, we grew into a secure, \"home\" kind of love. We chose each other in the messiest seasons -- and in doing so, we changed our stars. If it was possible for us, I promise it''s possible for you too. Just know this: this level of intimacy requires every part of you."}, {"type": "divider"}, {"type": "bold_text", "content": "Jeff"}, {"type": "text", "content": "We are going to dive deeper into these levels of intimacy, so that your RELATIONSHIP is tuned up so, with time, it will be easy to skip all of this and get straight to the connection of sexuality. Doesn''t that sound fun? So, let''s get started with the connection before the connection!"}, {"type": "subheading", "content": "Part 1: The Foundation -- Psychology of \"US\""}, {"type": "text", "content": "Focus: Trust, Commitment, Honesty, and Loyalty."}, {"type": "text", "content": "Before a couple can connect, they must feel safe. This page establishes the psychological \"soil\" in which intimacy grows."}, {"type": "text", "content": "Trust: The consistent knowledge that your partner acts in your best interest. It is built in \"sliding door\" moments -- choosing to turn toward your partner''s needs rather than away."}, {"type": "text", "content": "A \"sliding door\" moment is a term coined by Dr. John Gottman to describe the small, everyday interactions that serve as the building blocks of trust. They are called \"sliding doors\" because, in each moment, there is a door that opens: you can either enter and connect with your partner, or walk past and miss the opportunity."}, {"type": "text", "content": "These moments are rarely dramatic. They happen in the kitchen, in the car, or while lying in bed. While they seem small, they are where trust is either built or eroded."}, {"type": "subheading", "content": "The Anatomy of a Sliding Door Moment"}, {"type": "text", "content": "Every sliding door moment begins with a \"bid\" -- an attempt from one partner to get the other''s attention, affirmation, or affection. Take the time to pay attention to the little things."}, {"type": "text", "content": "Commitment: The decision to stay and work through the \"messy\" parts. It is the psychological safety net that allows for true vulnerability."}, {"type": "text", "content": "Honesty & Loyalty: Honesty is the bridge to reality; loyalty is the protection of that bridge. Loyalty means being your partner''s biggest advocate, especially when they are not present."}, {"type": "exercise", "title": "Foundation Questions", "prompt": "Questions for you to explore together. Take time to discuss each one, and make sure both partners have the chance to answer. These questions need to be answered honestly and completely, realizing that this may be difficult at times and may take a lot of time to complete. Keep it positive, and use the SPARK tool. Don''t rush this step.", "steps": ["What can I do to promote trust between us?", "Do you feel I have your back when we are with others? In what situations can I show up better for you?", "Can you help me understand how you feel about my commitment to you? Where can I improve?", "When the going gets tough, what do you need to feel that we are a team?"]}, {"type": "divider"}, {"type": "subheading", "content": "The SPARK Tool -- A Communication Lifeline"}, {"type": "text", "content": "Focus: How to talk when it hurts. When a trigger happens or a difficult truth needs to be shared, use SPARK:"}, {"type": "list", "items": ["S - See: Look at your partner. Listen fully with your heart. No interrupting. Show you are present with a nod or a gentle look.", "P - Pause & Probe: Take a breath. Ask: \"What felt hardest about that?\" or \"What did you need at that moment?\" Be curious, not defensive.", "A - Acknowledge & Validate: Reflect their feelings. \"I see that upset you -- it makes sense.\" Validation is not necessarily agreement; it is acknowledging their reality.", "R - Reconnect: Offer a repair. A sincere apology or a reaffirmation: \"I''m in this with you.\"", "K - Kindle: End with warmth. A long hug or a shared deep breath. Ask: \"What helps us feel close again?\""], "ordered": true}, {"type": "bold_text", "content": "Trisha"}, {"type": "text", "content": "You''ve had SPARK in your toolkit since the beginning; hopefully, it''s been a helpful guide for you throughout this program. It was a true lifeline for Jeff and me, particularly when old wounds flared up. I used to freeze or fawn when conflict arose, trying to \"keep the peace\" at any cost, but it left me resentful and unseen. Jeff would lean into anger and frustration. Everything changed when we learned to pause and truly validate one another''s feelings. It''s hard to be vulnerable at first, it was like exposing my raw heart, but learning and using these tools transformed our relationship. If you have not been using the SPARK tool, I highly encourage you to use them in your conversations. Try it gently with your partner; it''s not about being perfect, it''s about showing up with love in the hot mess."}, {"type": "divider"}, {"type": "bold_text", "content": "Jeff"}, {"type": "subheading", "content": "Part 2: Healing Betrayal Trauma -- The Safe Atmosphere"}, {"type": "text", "content": "This area is something I know a lot about. I have no excuses, I behaved badly at times in our marriage and caused betrayal. I followed roads to try and make myself feel better, looking for connections in places that were inappropriate, when Trisha was right in front of me wanting the same connection with me. We found through our own work, both separately and together, how to self regulate, how to look toward each other, but first we had to develop a safe environment for that to happen. And THAT was mostly up to me."}, {"type": "text", "content": "This is huge! Betrayal comes in many forms. It can be subtle, ie: making plans to go out with the guys on your 10th anniversary. Or it can be a deeply painful betrayal of sexual infidelity. Betrayal does not automatically spell divorce, as many would attest. If you have experienced the life-questioning depth of betrayal yet still feel a desire to save your marriage -- as many couples do -- there are a few things to hold on to."}, {"type": "text", "content": "Focus: Navigating hurt with patience and without judgment."}, {"type": "text", "content": "Again, betrayal doesn''t have to be a \"deal breaker\" if both partners commit to a healing-first environment, but these rules must be followed:"}, {"type": "bold_text", "content": "No Deadlines"}, {"type": "text", "content": "Healing takes as long as it takes. Phrases like \"It''s been a year, get over it\" are destructive. The nervous system requires consistency over time to reset. Consistency means being patient and not rolling your eyes when she says she feels ''triggered'' by this or that. You might as well start over at square one."}, {"type": "bold_text", "content": "The Betrayer''s Burden"}, {"type": "text", "content": "The partner who caused the hurt must lead with patience. This means answering the same questions with the same gentleness every time they are asked. It means enduring the times your partner is triggered by something that is familiar to the time you were deep in betrayal or causing your spouse pain."}, {"type": "text", "content": "However, I do not recommend dwelling on the details of the betrayal. The person who was betrayed will often want to know everything in an effort to make sense of what happened. The reality is that there is often no way to truly \"make sense\" of betrayal. Too much detailed information can actually make things worse and may cause the betrayed partner to spiral emotionally for a period of time, and no one knows how long that will take to improve. However, how YOU, the person who betrayed your spouse can have a lot to do with how long this takes. The closer you follow our directions on this, the faster trust can be developed and a new relationship forged."}, {"type": "text", "content": "For this reason, I recommend that the betrayer come clean about the betrayal with professional guidance -- honestly and completely -- while sparing details that create vivid visual images of the betrayal."}, {"type": "text", "content": "It is also important to avoid defensive language such as, \"I''m sorry I did it, but I wasn''t feeling heard either.\" Statements like this shift blame and fail to take full personal responsibility."}, {"type": "text", "content": "At the same time, if the betrayed partner is asking questions they genuinely need answered in order to heal and move forward, honest responses are essential. Some people heal by knowing less, while others heal by understanding the full picture. Trisha can help you to decipher the difference between knowing more and knowing less through a coaching call."}, {"type": "bold_text", "content": "Healing Over Judging"}, {"type": "text", "content": "Shift the mindset from \"I already said I''m sorry\" to \"I am here for your pain.\" Creating a safe atmosphere means allowing the betrayed partner to heal on their own timeline."}, {"type": "text", "content": "Follow the SPARK guidelines for conversation noted above. There will be moments when the betrayed partner falls apart and experiences serious doubts about you, the relationship, and even life itself. These moments can be intense and painful."}, {"type": "text", "content": "Even if the betrayer feels provoked, they must remain steady, keep control, and hold their temper. Stay grounded in your desire to support the person you hurt. Your role is to be present for their pain, even, probably especially when it is uncomfortable."}, {"type": "text", "content": "There may be times when the betrayed partner says things that are unfair or inaccurate. Even in those moments, the focus should remain on healing rather than defending. Disputes and clarifications can be addressed later, when emotions have settled."}, {"type": "text", "content": "As difficult as it may be for the betrayer to revisit painful memories and conversations, patience and kindness go a long way in rebuilding trust and repairing a broken marriage."}, {"type": "divider"}, {"type": "bold_text", "content": "Trisha"}, {"type": "text", "content": "This section hits very close to home for me. Many years ago, Jeff and I walked this exact, very excruciating road ourselves."}, {"type": "text", "content": "The betrayal felt like our entire life had been thrown into a blender. I remember the shock that stopped my breath. The endless questions looping through my mind at 3am. I remember thinking, \"How did I get here?\" I felt like I was sleeping beside the enemy. With that mindset, sleep itself became elusive for years. Physical intimacy where I truly felt safe? That felt impossible. The exhaustion, combined with the loss of trust in who I was and who I was with, cut so deeply that I began to question everything -- my identity, my relationship, and whether anything in my world had ever truly been real."}, {"type": "text", "content": "I remember D-day -- the day discovery hit. The room spun. My chest tightened like a vise. I couldn''t stop shaking. My nervous system screamed the brutal double bind: the very person I needed most for safety had suddenly become the very source of my deepest wound imaginable."}, {"type": "callout", "icon": "heart", "content": "I need you for safety... and you are the one who hurt me."}, {"type": "text", "content": "That conflict tore through me like a vicious storm. I became hypervigilant. Intrusive thoughts and images flooded my mind. Sleep was nearly impossible. Some moments I felt numb, and other moments waves of emotion would crash over me without warning."}, {"type": "text", "content": "I remember standing in the grocery store one day and suddenly bursting into tears right there in the aisle, completely unable to stop. I felt embarrassed and frustrated with myself because it seemed like I couldn''t go anywhere and hold it together. Most days, I simply couldn''t."}, {"type": "text", "content": "Looking back, I can see how my nervous system was desperately trying to find relief."}, {"type": "text", "content": "In those early days, the pain was so overwhelming I craved escape -- any rush to drown it out. I can relate so much to that scene in the movie Twilight: New Moon when Edward breaks up with Bella and she throws herself onto a motorcycle for a reckless ride. She needed speed, adrenaline, anything to feel alive again and quiet the ache. For me, it was zip-lining over and over. Not to hurt myself, but to chase that rush -- the wind, the height, the momentary freedom from the torment inside. The adrenaline was significant; it gave me a brief break from the grief."}, {"type": "text", "content": "Today I still enjoy zip-lining, but it is no longer a desperate need. At the time, though, it made sense. My body was searching for anything that would shift the intensity of what I was feeling inside. Because the truth was, nothing felt safe anymore. I didn''t even trust myself. Not inside my own body. Not inside my own home."}, {"type": "text", "content": "For a long time, I thought something was wrong with me, but nothing was wrong with me. Those reactions were not weakness. They were my nervous system''s intelligent attempt to protect me after a relational tsunami."}, {"type": "text", "content": "Healing did not happen quickly, and it definitely was not linear. I wanted it to look simple. I wanted it to look like this: hurt -> repair -> forgive -> recover -> move on."}, {"type": "text", "content": "But the real journey looked more like this: stabilize somewhat in the chaos -> get severely triggered -> regulate my body -> get triggered again -> try to wrap my head around what was happening -> triggered again -> repair together -> another trigger -> regulate a little faster -> slowly deepen safety over time."}, {"type": "text", "content": "Some days felt like progress. Other days felt like I was sliding backward off a cliff. But over months and years, the triggers came less often, lasted for shorter periods, and slowly lost their power to completely derail me."}, {"type": "text", "content": "Along the way I learned something I never expected to learn. It is possible to hold grief and hope in the same body."}, {"type": "text", "content": "Jeff and I began having honest conversations. I tried to hold back from asking too many detailed questions, even though part of me wanted to know absolutely everything. I realized the more details the more it hurt me."}, {"type": "text", "content": "At first, those conversations were incredibly painful. But over time, the intensity softened. I was able to stay present instead of shutting down, and little by little, a sense of safety began to return."}, {"type": "text", "content": "Trust did not come back because of his promises. Trust returned through patterned safety over time."}, {"type": "text", "content": "Jeff had to fully own what had happened. That meant complete transparency, not sharing every gritty detail, but being open and honest where it mattered."}, {"type": "list", "items": ["It meant giving me access to his phone and devices when I needed reassurance, answering hard questions truthfully, taking accountability without defensiveness or minimizing, and consistently following through on boundaries and commitments.", "Just as important, he learned to sit in my pain with me. Instead of explaining it away or trying to rush the healing process, he listened. He validated the hurt. He allowed the truth of the damage to be seen."], "ordered": false}, {"type": "text", "content": "Through that process we realized something important. The goal was never to return to \"normal.\""}, {"type": "text", "content": "Normal had been shattered."}, {"type": "callout", "icon": "lightbulb", "content": "Betrayal became the doorway to something deeper. We were not rebuilding the relationship we had before. We were building something entirely new; a relationship with stronger wiring, a firmer foundation, clearer boundaries, and a level of emotional awareness we had never known before."}, {"type": "text", "content": "We were not rebuilding the old house. We were building a completely brand new one. In that process, both of us had deep work to do."}, {"type": "text", "content": "I was healing from shock and grief, from the loss of trust and safety, and from a deep rupture in my sense of identity. I had to rebuild confidence in myself and slowly begin putting the pieces of my life back together, and so importantly, our children''s lives as well. They were deeply affected by this trauma too."}, {"type": "text", "content": "Jeff had to face his own wounds: shame, disconnection from his values, unhealthy coping patterns, avoidance, and the rupture in his integrity."}, {"type": "text", "content": "Both experiences mattered. Both wounds deserved compassion and healing."}, {"type": "text", "content": "During that season, our faith became an incredible anchor for us. We turned to Christ because we needed miracles and strength far beyond our own. We were also surrounded by family, church family, and a few friends who rallied around us and carried us in ways we could not have managed alone."}, {"type": "text", "content": "Looking back now, I can see how often the Lord carried us through moments we could never have survived on our own."}, {"type": "text", "content": "I truly believe one of the reasons so many relationships remain broken is because people try to heal them without inviting Christ into the process. When we allowed Him into our marriage, He softened hearts, created humility, and helped guide us through the healing we could not accomplish by ourselves."}, {"type": "text", "content": "Even now, triggers surface occasionally."}, {"type": "text", "content": "But we have learned something powerful about them."}, {"type": "callout", "icon": "lightbulb", "content": "Triggers are not setbacks. They are invitations to investigate. A trigger does not mean healing is failing. It means there is still unprocessed information in your nervous system asking for safety, understanding, and integration."}, {"type": "text", "content": "When one hits, we slow the moment down. Pause. Regulate your nervous system. These are simple techniques you''ve already learned and we still use today:"}, {"type": "list", "items": ["4-7-8 breathing: Inhale quietly for 4 counts, hold for 7, exhale through the mouth for 8. Repeat four times to calm the vagus nerve.", "5-4-3-2-1 grounding: Name five things you see, four you can touch, three you hear, two you smell, one you taste. This brings the nervous system back into the present moment.", "Extended exhale breathing: Inhale normally, then exhale longer than the inhale. This signals safety to the body.", "Gentle self-touch or co-regulation: Place a hand on your heart or belly, or if it feels safe, reach for your partner''s hand or a hug. Safe connection helps the body relearn trust."], "ordered": false}, {"type": "text", "content": "When triggers arise:"}, {"type": "list", "items": ["Pause", "Regulate", "Name what is happening -- \"this is a trigger. My nervous system is protecting me from the past.\"", "Repair together: We ask questions. We listen. We validate. We reconnect."], "ordered": false}, {"type": "text", "content": "This turns pain into healing fuel instead of something that controls the relationship."}, {"type": "text", "content": "Forgiveness also changed meaning for me. It was not something I could force. When forgiveness is rushed, it often becomes suppression or self-abandonment."}, {"type": "text", "content": "Real forgiveness grew slowly as safety returned, as grief was honored, and as I began trusting myself again."}, {"type": "callout", "icon": "heart", "content": "You do not forgive to excuse what happened, you forgive to set yourself free."}, {"type": "text", "content": "Jeff and I survived the fire -- every layer -- through Christ, honesty, humility, and unwavering commitment to healing over shame. We emerged stronger, more connected, and more honest than we ever imagined possible."}, {"type": "text", "content": "Triggers still surface on rare occasions, but now we meet them together with tools and compassion instead of fear."}, {"type": "text", "content": "If you are in this kind of pain right now, hold on. You are not alone."}, {"type": "text", "content": "You do not need a perfect story or every answer to begin healing. You need enough truth to orient yourself, enough safety for your nervous system to settle, and enough support to process what happened."}, {"type": "text", "content": "Betrayal may be one of the most devastating chapters in your story, it was for us. But with courage, honesty, a commitment to healing over shame, and the right support, it can also become one of the most transformative."}, {"type": "text", "content": "Not because what happened was okay, but because you chose to face it head on and grow through it."}, {"type": "text", "content": "Jeff and I are living proof that healing is possible."}, {"type": "text", "content": "For so long, I never felt safe in bed with him -- safe enough to sleep, to truly rest, or to enjoy emotional and physical intimacy. But healing can change things. Today I can sleep peacefully, feel rested, and experience intimacy with a sense of safety that once felt impossible."}]}');

  -- Child 2: The Connection Layers
  INSERT INTO lessons (module_id, parent_lesson_id, title, sort_order, is_preview, content_json)
  VALUES (mod7_id, parent_id, 'The Connection Layers', 6, true, '{"estimated_minutes": 25, "blocks": [{"type": "heading", "content": "The Connection Layers"}, {"type": "bold_text", "content": "Jeff"}, {"type": "subheading", "content": "Part 3: Verbal Intimacy -- Beyond \"I Love You\""}, {"type": "text", "content": "Focus: Tone, Gratitude, and Affirmation."}, {"type": "text", "content": "Words are the atmosphere of the relationship."}, {"type": "text", "content": "The Power of Tone: Research shows the way you say something matters more than what you say. Aim for a \"soft startup\" in every conversation. I can''t overemphasize this. It''s something I am working on personally. The SPARK techniques can help a ton here!"}, {"type": "text", "content": "Specific Gratitude: Move from \"Thanks\" to \"I noticed you took the trash out so I wouldn''t have to, and I felt really cared for.\" It is best to have specific items of gratitude."}, {"type": "text", "content": "Words of Affirmation: Identify the character traits you admire in your partner and tell them why you value who they are, not just what they do. But be sincere -- don''t do this flippantly. In the film While You Were Sleeping, Sandra Bullock''s character is consoled by a neighbor who, while trying to comfort her, rolls his eyes and makes a rushed gesture. The gesture completely undermines the message. Similarly, your tone and body language with your spouse can ruin even the most heartfelt words. Be genuine."}, {"type": "divider"}, {"type": "bold_text", "content": "Trisha"}, {"type": "text", "content": "While tone has not been my biggest personal struggle, it has certainly been a challenge in our relationship. When Jeff is stressed or tired, his tone can sharpen, not because he doesn''t love me, but because his nervous system is running fast. I initially interpreted that sharpness as rejection, when the reality was simply that he was exhausted and dysregulated."}, {"type": "text", "content": "What changed everything for us was awareness. Instead of assuming the meaning behind his tone, I had to learn the art of asking curious questions. Jeff has a great saying: \"Be curious before furious!\" Rather than reacting to the sting, I started checking in to see what was really happening beneath the surface. Over time, I got better at asking clarifying questions and practicing patience. Sometimes he didn''t even know what was wrong, or that when he was overwhelmed, he might lash out. We''ve come a long way -- but we''re still not perfect!"}, {"type": "list", "items": ["\"Did I misunderstand what you just said?\"", "\"Is there something else going on?\""], "ordered": false}, {"type": "text", "content": "When Jeff began intentionally softening his tone, the entire \"weather\" of our home shifted. I no longer felt like I had to stay braced for impact; instead, I finally felt safe."}, {"type": "callout", "icon": "lightbulb", "content": "Questions protect connection. They stop the \"freeze or fawn\" cycle and invite the other person back into the room."}, {"type": "text", "content": "We''ve also found that specific gratitude is a superpower. When appreciation is detailed and sincere, it builds a foundation of security. When it''s vague or rushed, it rarely lands well. When Jeff notices something specific, something about my effort or character, it lands so differently than a quick \"thanks.\""}, {"type": "text", "content": "Words are not small. They shape the atmosphere of a relationship, and the atmosphere you create together will either nurture intimacy or slowly erode it."}, {"type": "divider"}, {"type": "bold_text", "content": "Jeff"}, {"type": "subheading", "content": "Part 4: Emotional Intimacy -- Ending the Mind-Reading"}, {"type": "text", "content": "Focus: Vulnerability and Shared Realities."}, {"type": "text", "content": "We often punish our partners for failing a test they didn''t know they were taking."}, {"type": "text", "content": "The End of Mind-Reading: Erase from your mind thoughts like: \"We''ve been married for 15 years, he or she should know this about me by now.\" Explicitly state your needs. \"I am feeling overwhelmed and I need a 10-minute snuggle,\" instead of being cold and hoping they notice. This can be a problem for each partner, but usually there is one that is worse than the other. You know who you are!"}, {"type": "text", "content": "Most people need reminders about some things. Give your partner some grace when they forget something. But if you are the forgetter, take responsibility and don''t gaslight your partner, (\"You never told me about that appointment,\" when you surely were told). Vice versa, if your partner forgets, it is acceptable to be patient and kind in reminding them."}, {"type": "text", "content": "The Vulnerability Cycle: When you share a fear, you invite your partner to be your protector. This creates a bond that lesser \"facts\" cannot touch. When you know each other''s weaknesses, you can complement each other with your personal strengths. In the event that your partner and you have the same weakness, well, that is why coaching was invented!"}, {"type": "text", "content": "Emotional Safety: Ensuring that when your partner shares a \"dark\" or \"raw\" feeling, you hold it like a precious object rather than a weapon to be used later. Avoid criticism at all costs. This is a trap that some people cannot seem to grasp. But you know, now you can use your green zone to open up your ability to accept and love. Refer to \"SPARK\" above."}, {"type": "divider"}, {"type": "bold_text", "content": "Trisha"}, {"type": "subheading", "content": "The Costco Lesson"}, {"type": "text", "content": "Mind-reading is a silent epidemic in relationships. We all do it. But if we stop and really think about it... does it ever actually work?"}, {"type": "text", "content": "I know I''ve done it. I used to carry these silent expectations and think, \"If Jeff really knew me, he would just know what I need.\""}, {"type": "text", "content": "Which sounds very romantic. But in real life, it''s a terrible communication strategy."}, {"type": "text", "content": "Because Jeff, as wonderful as he is, did not come with built-in psychic abilities. Dang it."}, {"type": "text", "content": "One of my biggest lightbulb moments about this happened during a very normal trip to Costco. We had ordered a reprinted family photo, and Jeff ran inside to grab it while I stayed in the car. Now in my mind, there was a very clear plan for how this was supposed to go."}, {"type": "text", "content": "Jeff would go inside. He would pick up the photo. He would open the package. He would carefully inspect the photo. Make sure everything looks perfect. And then he would proudly return to the car having completed his assignment like a highly trained Costco photo-inspection specialist."}, {"type": "text", "content": "All of this was very clear. In my head."}, {"type": "text", "content": "So Jeff comes back out, gets in the car, and we start driving home. A few minutes later I ask, \"So how does the picture look?\" And Jeff says, \"I don''t know.\""}, {"type": "text", "content": "I said, \"Wait... what do you mean you don''t know?\" He says, \"I didn''t look at it.\""}, {"type": "text", "content": "Now I''m confused. \"Wait... you didn''t check it before you left the store?\" And Jeff just calmly looks over at me and says, \"No. You never asked me to look at it.\""}, {"type": "text", "content": "And in that moment it hit me."}, {"type": "text", "content": "I had an entire unspoken plan in my head that I expected him to magically follow, without ever actually telling him. Apparently my communication strategy at the time was to think the instructions really loudly and hope Jeff picked them up through invisible marital telepathy. Shockingly... that did not work."}, {"type": "text", "content": "So we pulled over to the side of the road, opened the box, and took the family photo out right there in the car to inspect it. Thankfully it looked great and we did not have to drive all the way back to Costco. But that moment stuck with me."}, {"type": "text", "content": "Because I realized something important: I had expected Jeff to follow instructions I had never actually spoken out loud."}, {"type": "text", "content": "Now, instead of assuming he knows what I''m thinking, I''ve learned it''s far healthier to slow down, ask a question, and simply state my needs."}, {"type": "callout", "icon": "heart", "content": "Ladies, our men cannot read our minds! We have to tell them what we are thinking."}, {"type": "text", "content": "By cutting through the \"guesswork\" of mind-reading and choosing clarity instead, you hand your partner the keys to your heart. You are showing them exactly how to love you, how to protect you, and how to win with you. There is no greater intimacy than being fully known, and that only happens when you have the courage to make yourself visible."}, {"type": "text", "content": "Remember, clear communication saves marriages, and occasionally unnecessary trips back to Costco."}, {"type": "divider"}, {"type": "bold_text", "content": "Jeff"}, {"type": "exercise", "title": "Emotional Intimacy Questions", "prompt": "Ask each other these questions:", "steps": ["Are you feeling stressed about something that I might not be aware of?", "Is there a moment lately where you felt a ''pinch'' or a disconnect with me, but didn''t feel like you could bring it up at that moment?", "Is there anything that you are struggling to like about yourself right now? How can I support you in that struggle?", "What can I do to help you feel deeply cared for?"]}, {"type": "divider"}, {"type": "subheading", "content": "Part 5: Cognitive & Intellectual Intimacy"}, {"type": "text", "content": "Focus: Shared Curiosity and \"Curious Before Furious.\" This is the meeting of the minds -- respecting and engaging with your partner''s thoughts."}, {"type": "text", "content": "Curious Before Furious: When your partner does something that confuses or upsets you, your first internal question should be: \"What am I missing?\" rather than \"How could they?\""}, {"type": "text", "content": "Sharing the \"Why\": Don''t just share what you think -- share why you think it. This is where my favorite phrase comes in again: \"Curious before Furious!\" It gives you that crucial one- to five-second pause, allowing your frontal cortex to engage instead of letting your amygdala take over. Once the amygdala hijacks your response, it''s much harder to rein it back in."}, {"type": "text", "content": "Counting to five can help, but asking a thoughtful question works even better. Questions activate higher-level thinking, keeping you in the \"green zone\" and engaging your brain rather than letting your \"critter brain\" run the show. It''s a way to monitor your heart rate, regulate your emotions, and -- trust me -- avoid that panicked feeling that hits in the middle of the \"red zone.\""}, {"type": "text", "content": "The \"Dreamer\" Exercise: Regularly ask about your partner''s changing dreams and goals. People evolve; stay curious about who they are becoming today."}, {"type": "divider"}, {"type": "bold_text", "content": "Trisha"}, {"type": "subheading", "content": "The Landscape of the Mind"}, {"type": "text", "content": "I like to think of intellectual intimacy as an invitation to tour your partner''s internal world. When we have been together for a long time, we start to think we''ve seen every room in their house. We assume we know their opinions, their reactions, and their reasons."}, {"type": "text", "content": "People are not static; we are constantly shaped by our experiences. Choosing to be \"curious before furious\" is like saying, \"I value understanding your experience more than proving my assumption right.\" It takes a lot of pressure off the relationship when you realize you don''t need to be an expert on your partner -- you get to be a student of them."}, {"type": "text", "content": "By asking, \"What am I missing?\" you transform a potential battlefield into a classroom. You''re not just avoiding a fight; you''re building a bridge to the person your partner is becoming today, rather than clinging to the person you thought they were yesterday."}, {"type": "divider"}, {"type": "bold_text", "content": "Jeff"}, {"type": "exercise", "title": "Intellectual Intimacy Questions", "prompt": "Ask your partner these questions together, and write down your answers. You will want to return to this another day.", "steps": ["What is something you are looking forward to that includes us?", "What is a topic that we need to discuss, but keep avoiding, that is getting in the way of our intimate relationship?", "What specifically can I do to decrease your stress regarding our relationship?", "How do you feel when I try hard to listen and understand without getting angry?"]}]}');

  -- Child 3: Spiritual & Physical Intimacy
  INSERT INTO lessons (module_id, parent_lesson_id, title, sort_order, is_preview, content_json)
  VALUES (mod7_id, parent_id, 'Spiritual & Physical Intimacy', 7, true, '{"estimated_minutes": 25, "blocks": [{"type": "heading", "content": "Spiritual & Physical Intimacy"}, {"type": "bold_text", "content": "Jeff"}, {"type": "subheading", "content": "Part 6: Spiritual Intimacy -- Shared Meaning"}, {"type": "text", "content": "Focus: Higher Power, Nature, and Purpose, Unity."}, {"type": "text", "content": "Connecting on a level that transcends the physical and intellectual."}, {"type": "text", "content": "The Bible has a lot to say on this topic, here are just a few:"}, {"type": "text", "content": "Moving from \"I\" to \"We.\""}, {"type": "quote", "content": "That is why a man leaves his father and mother and is united to his wife, and they become one flesh.", "attribution": "Genesis 2:24"}, {"type": "list", "items": ["The Spiritual Insight: This \"oneness\" (Hebrew: Echad) does not mean losing your identity; it means creating a new, unified entity. In betrayal recovery, this verse reminds the couple that a wound to one is a wound to both, and a victory for one is a victory for both.", "SPARK Application: Use the S (See) step to look at your partner and realize they are not your opponent, but a part of you."], "ordered": false}, {"type": "text", "content": "Love as the ultimate unifying force."}, {"type": "quote", "content": "And over all these virtues put on love, which binds them all together in perfect unity.", "attribution": "Colossians 3:14"}, {"type": "list", "items": ["The Spiritual Insight: Think of love as the \"belt\" that holds the armor together. Without it, honesty, loyalty, and passion fall apart. It is a choice you \"put on\" every morning, even on the days you don''t feel \"in love.\"", "SPARK Application: Use the A (Acknowledge) step to recognize that even when you disagree, the \"bond\" of your commitment is more important than being right."], "ordered": false}, {"type": "text", "content": "Alignment of direction."}, {"type": "quote", "content": "Do two walk together unless they have agreed to do so?", "attribution": "Amos 3:3"}, {"type": "list", "items": ["The Spiritual Insight: Unity requires a shared destination. This verse is perfect for the Intellectual Intimacy section of your program. It asks: \"Are we heading toward the same future?\"", "SPARK Application: Use the P (Pause & Probe) step to ask: \"Are we walking in the same direction today? What can I do to get back in step with you?\""], "ordered": false}, {"type": "text", "content": "Other Spiritual Insights:"}, {"type": "list", "items": ["Sacred Shared Time: Whether it is praying together, attending church, or meditating, this aligns your \"North Stars.\"", "Nature as Connection: Enjoying the outdoors together fosters a sense of awe. Awe reduces the \"ego\" and makes the couple feel like a unified team in a vast world.", "Gratitude to a Higher Power: Practicing gratitude together for the blessing of the relationship itself. Gratitude for each other''s strengths and weaknesses that you can be bound together in synergy and direction."], "ordered": false}, {"type": "divider"}, {"type": "bold_text", "content": "Trisha"}, {"type": "text", "content": "Spiritual intimacy has been one of the most grounding forces in our marriage, especially in the seasons when everything felt like it was completely coming apart."}, {"type": "text", "content": "There were times when Jeff and I truly did not know how we were going to make it through the challenges we were facing. We didn''t have the answers. We didn''t have the strength."}, {"type": "text", "content": "But we knew where to turn."}, {"type": "text", "content": "Many nights we knelt together in prayer, not because everything was okay, but because it wasn''t. Sometimes the prayers were full of tears. Sometimes the words barely came out at all. There were moments when all we could do was sit there in the quiet and let our hearts break open before God."}, {"type": "text", "content": "And somehow, in those sacred moments, something began to shift. We realized we were not carrying the weight of our marriage alone."}, {"type": "callout", "icon": "heart", "content": "Christ carried us in ways we simply could not carry ourselves."}, {"type": "text", "content": "When everything felt heavy... when trust felt fragile... when our hearts were tired and worn thin... turning to Him softened something in both of us. It reminded us that we were not enemies standing on opposite sides of a battlefield. We were two imperfect people trying to find our way back to each other, with the Savior walking between us."}, {"type": "text", "content": "When you invite God into your relationship, the entire focus changes. It stops being about winning the argument or proving who is right. It becomes about humility. About forgiveness. About surrendering your pride and asking for help when you simply do not have the strength on your own."}, {"type": "text", "content": "And this is something Jeff and I know deep in our bones now:"}, {"type": "text", "content": "When two people keep turning their hearts toward Christ -- even in their weakest, most broken moments, He has a way of doing what feels impossible. He heals what feels shattered. He softens what feels hardened. And little by little, He gently guides two hearts back to each other."}, {"type": "divider"}, {"type": "bold_text", "content": "Jeff"}, {"type": "subheading", "content": "Part 7: Physical Intimacy -- The Skin-to-Skin Foundation"}, {"type": "text", "content": "Focus: Before and beyond sex; safe touch."}, {"type": "text", "content": "Non-sexual touch tells the nervous system: You are home. You are safe."}, {"type": "text", "content": "Gentle Proximity: Sitting close enough that your shoulders touch; a hand on the small of the back while walking."}, {"type": "text", "content": "The 20-Second Hug: This is the biological \"reset button.\" It lowers cortisol and raises oxytocin."}, {"type": "text", "content": "Touch without \"The Ask\": Establish that physical affection does not always have to be a prelude to sex. This removes the pressure and allows the partner (especially a betrayed partner) to enjoy touch without anxiety."}, {"type": "divider"}, {"type": "bold_text", "content": "Trisha"}, {"type": "text", "content": "I love this section because it reminds us that intimacy does not begin in the bedroom. It begins in the quiet, ordinary moments of a life together."}, {"type": "text", "content": "As I shared earlier, when trust has been broken those moments can feel incredibly heavy. Even a simple touch can feel complicated for a season. Healing does not happen overnight. It unfolds slowly as emotional safety returns."}, {"type": "text", "content": "For a long time my nervous system lived on high alert. My body was constantly scanning for danger, which made it hard to truly relax. What Jeff and I eventually discovered is the powerful science of co-regulation."}, {"type": "text", "content": "When we hold hands or sit close, we are not just being sweet. Touch releases oxytocin, lowers cortisol, the stress hormone, and gently signals to the critter brain, the fear center of the brain, that it can stand down. Over time, safe touch helps the body begin to associate your partner with comfort again instead of threat."}, {"type": "text", "content": "And honestly, it was the smallest things that mattered the most."}, {"type": "list", "items": ["A hand on my arm while making dinner.", "Sitting shoulder to shoulder on the porch watching the sunset.", "A quiet moment together at the end of the day."], "ordered": false}, {"type": "text", "content": "Those simple moments slowly taught my body it was safe to stop searching for the exit and begin to feel at home again."}, {"type": "text", "content": "We didn''t just \"get over it.\" We rebuilt connection intentionally -- through small rituals of presence, eye contact, and celebrating tiny victories along the way. And I can tell you from experience, we have moved mountains to get where we are today."}, {"type": "subheading", "content": "Positive Steps Toward Restoration"}, {"type": "bold_text", "content": "The Morning Anchor"}, {"type": "text", "content": "Before getting out of bed, spend about 30 seconds simply holding hands or letting your feet touch. It quietly anchors the day in us before the world starts pulling you in a hundred directions."}, {"type": "bold_text", "content": "The Six-Second Kiss"}, {"type": "text", "content": "Dr. Gottman calls this a \"kiss with potential.\" It''s just long enough to feel a connection instead of a routine."}, {"type": "bold_text", "content": "Safe-Word Silence"}, {"type": "text", "content": "If touch begins to feel heavy or triggering, create a simple word or gesture that means, \"I need a moment, but I''m still here.\" It protects the boundary without creating rejection."}, {"type": "callout", "icon": "heart", "content": "You are not just rebuilding a marriage and a new life. You are reclaiming your peace, your safety, and your connection."}, {"type": "divider"}, {"type": "bold_text", "content": "Jeff"}, {"type": "exercise", "title": "Reflection & Connection", "prompt": "Ask each other these questions and write down your feelings and answers:", "steps": ["What is a fear you carry about yourself that you are most afraid of me truly seeing?", "When it comes to physical intimacy, what kind of touch feels non-threatening and possibly calming?", "If you could have me understand one thing that would help me connect to the inner you, what would it be?", "What touch, kiss, or caress gives your body the signal of safety?"]}, {"type": "divider"}, {"type": "subheading", "content": "Part 8: Sexual Intimacy I -- The Dual Control Model"}, {"type": "text", "content": "We cannot have an intimacy discussion and not talk about sex itself. So, here we go. Buckle up!"}, {"type": "text", "content": "There are two parts to this discussion: Dual Control and Altruistic Pleasure (concentrating on your partner and your dual connection)."}, {"type": "text", "content": "Focus: Removing the Brakes."}, {"type": "text", "content": "Transitioning into the sexual realm requires understanding how \"arousal\" actually works in a long-term relationship. Now that you are more comfortable with each other and feeling you can let your walls down, each of you has the opportunity to learn how to communicate physically."}, {"type": "text", "content": "Accelerators vs. Brakes: Most \"low libido\" issues are actually \"high brake\" issues. Brakes include stress, lack of emotional safety, or feeling \"unseen.\" Performance anxiety -- the worry that your body won''t respond -- can also act as a brake. Accelerators are the factors that encourage sexual intimacy."}, {"type": "text", "content": "Removing the Brakes and Bricks: Work together to identify what puts the \"brakes\" on for each other. A \"brick\" is a heavy topic or emotion that leans heavily on the brakes, effectively stopping the process. It could be something as simple as unfinished chores or a lack of verbal affirmation."}, {"type": "text", "content": "Mutual Visibility: There is more to seeing than opening your eyes. True visibility means understanding where your spouse \"is\" in the moment and \"reading the room\" before you begin. Also, a good sense of warming up before jumping in."}, {"type": "divider"}, {"type": "bold_text", "content": "Trisha"}, {"type": "text", "content": "I want to pause here and go a little deeper, because for many of us the \"brakes\" are not just about a busy schedule, a messy kitchen, or the overwhelm of kids and careers. Very often the brakes are rooted in survival."}, {"type": "text", "content": "When you''ve experienced trauma or a deep breach of trust, your body''s natural response is to protect itself. In our marriage, my brakes were often slammed on because my nervous system simply didn''t feel the safety it needed to let go."}, {"type": "text", "content": "What Jeff calls \"the brakes,\" I experienced as a physical wall. And over time I''ve learned that understanding our unique brakes and accelerators can be incredibly transformative for any relationship, whether trauma is present or not. Making love is not just about sex. It is about shared vulnerability. It is the science of feeling safe enough to finally drop your guard."}, {"type": "text", "content": "As Jeff and I began identifying the \"bricks\" -- the unspoken hurts, the constant scanning, the hypervigilance my body carried, we slowly started clearing the path. I can tell you from experience that walking through what I often call the healing fire does get easier as emotional safety returns, one step at a time. When safety grows, couples begin to find their rhythm again."}, {"type": "text", "content": "I share this part of our story because these struggles affect far more relationships than people realize. And even if betrayal is not part of your story, your nervous system has likely shut down at times in response to stress or overwhelm. My hope is that this sheds light on tools that can help guide you back toward safety and connection."}, {"type": "subheading", "content": "Positive Steps Toward Removing the Brakes"}, {"type": "bold_text", "content": "The Brick Check-In"}, {"type": "text", "content": "Once a week, gently ask: \"Is there anything feeling like a brick on your brakes right now?\" This allows you to address stress or hurt before it quietly builds distance."}, {"type": "bold_text", "content": "Safety Signals"}, {"type": "text", "content": "Agree on a way to communicate when the brakes are on without it feeling like rejection. Something as simple as: \"I really want to be close to you, but my system feels a little crowded right now. I need to find some emotional safety first.\""}, {"type": "bold_text", "content": "The Science of Connection"}, {"type": "text", "content": "Proximity and touch release dopamine and endorphins, creating a feedback loop of calm and connection. When emotional safety is present, couples often begin to mirror each other -- heart rates slow, breathing settles, and the body relaxes. This is the sweet spot where physical intimacy becomes deeply healing."}, {"type": "callout", "icon": "lightbulb", "content": "You aren''t just learning about intimacy. You are reclaiming the peace of being fully known and fully safe. It is the journey from protection to connection -- one step, and sometimes one mountain, at a time."}]}');

  -- Child 4: Sexual Connection & Action Plan
  INSERT INTO lessons (module_id, parent_lesson_id, title, sort_order, is_preview, content_json)
  VALUES (mod7_id, parent_id, 'Sexual Connection & Action Plan', 8, true, '{"estimated_minutes": 25, "blocks": [{"type": "heading", "content": "Sexual Connection & Action Plan"}, {"type": "bold_text", "content": "Jeff"}, {"type": "subheading", "content": "Part 9: Sexual Intimacy II -- Altruistic Pleasure"}, {"type": "text", "content": "Focus: Connection, Understanding, and The Afterglow."}, {"type": "text", "content": "Sex is the \"cherry on top\" of the safety built in the previous parts."}, {"type": "text", "content": "Altruistic Pleasure: Focus on the other''s satisfaction as a gift. When both partners have this \"service\" mindset, the pressure to \"perform\" disappears, and pleasure increases."}, {"type": "text", "content": "Working Together: Communicate what feels like \"love\" in the moment. Use your cognitive intimacy tools to ask questions rather than guessing. Read the room: sometimes asking questions spoils the mood. Keep your eyes open occasionally and see how your partner responds."}, {"type": "text", "content": "Climax: Always a great destination, but not always achieved. Be grateful for getting there, have grace and understanding if not. Sex evolves, and as you explore your partner''s likes and dislikes, your connection grows."}, {"type": "text", "content": "The Afterglow: The 15 minutes after sex are the most important for bonding. Use this time for cuddling, gentle words, and \"K\" (Kindle) from the SPARK tool."}, {"type": "text", "content": "See the Appendix at the end of this module and do the \"yes, no, maybe\" test."}, {"type": "divider"}, {"type": "bold_text", "content": "Trisha"}, {"type": "text", "content": "I love that Jeff calls sex the \"cherry on top,\" because for a long time it felt like a distant shore I wasn''t sure I would ever reach again."}, {"type": "text", "content": "After betrayal or when your heart has been hurt, the bedroom can feel like the most vulnerable place on earth. For a long season in our marriage, safety there felt impossible. But what I eventually discovered is that when emotional safety begins to return, intimacy can become something very different than it once was."}, {"type": "text", "content": "It can become a place of rest and reset."}, {"type": "text", "content": "Altruistic pleasure is the beautiful mindset of saying, \"Your joy matters to me.\" It shifts the focus away from performance and back to presence. Instead of worrying about whether everything is \"working\" or whether the moment is perfect, the focus becomes caring for the person in front of you."}, {"type": "text", "content": "And something powerful happens when that shift takes place. When your attention turns toward your partner''s joy, your own nervous system begins to soften. The pressure lifts. The brakes quiet down. What once felt tense or fragile slowly becomes safe again."}, {"type": "text", "content": "I can tell you from experience that even your physical connection can be forged into something deeper through this process. Intimacy is not a pass-or-fail grade based on a climax. It is a conversation."}, {"type": "text", "content": "Sometimes that conversation is playful and light. Sometimes it is quiet and deeply healing. And sometimes it is simply two people choosing to stay connected."}, {"type": "text", "content": "One of my favorite parts of this restoration is what happens afterward."}, {"type": "text", "content": "Those quiet minutes of afterglow are often where the deepest repair happens. This is where the oxytocin peaks, where nervous systems settle, and where the world finally feels far away. It is a small window of peace where two people can simply rest in the connection they fought so hard to rebuild."}, {"type": "text", "content": "Whether you have crossed deep waters to get here or you are just beginning to clear the path, remember this moment matters."}, {"type": "text", "content": "This is the space where you are fully known."}, {"type": "subheading", "content": "Tips for a Sacred Connection"}, {"type": "bold_text", "content": "The Eyes-Open Moment"}, {"type": "text", "content": "Like Jeff mentioned, try to catch each other''s gaze. There is a unique kind of soul-safety that happens when you realize your partner is truly present with you."}, {"type": "bold_text", "content": "The \"Kindle\" Whisper"}, {"type": "text", "content": "During those quiet moments afterward, whisper one thing you love about your partner''s heart -- not their body. It anchors the physical connection back into emotional safety."}, {"type": "bold_text", "content": "Grace for the Journey"}, {"type": "text", "content": "Some nights will feel like a breakthrough. Some will just feel like a Tuesday. Be grateful for the effort, the closeness, and the fact that you are still choosing each other."}, {"type": "callout", "icon": "heart", "content": "You are reclaiming the peace of being fully known. And it truly does get better -- one breath, one touch, and one beautiful afterglow at a time."}, {"type": "divider"}, {"type": "bold_text", "content": "Jeff"}, {"type": "subheading", "content": "A Word About Pornography and Masturbation"}, {"type": "text", "content": "Studies have shown that pornography is a graphic fantasy and not even close to a ''substitute'' for real connection and sexuality. Habitual use can reduce the brain''s ability to experience sexual pleasure and connection during real-life intimacy. Over time, this can make marital sex less satisfying -- which is not the goal of this course. Masturbation can be useful for exploring what kinds of touch you enjoy, but when done habitually, especially alongside pornography use, it can significantly dampen normal in-person sexual response. For this reason, we recommend avoiding habitual masturbation and pornography, despite widespread and easy availability."}, {"type": "text", "content": "Another concern with pornography is that it often portrays acts that a person or their spouse would never personally engage in. Exposure to this material can create pressure on a spouse''s personal boundaries, sometimes leading to those boundaries being compromised. This can result in mental or even physical harm, and at minimum, it often fosters resentment."}, {"type": "text", "content": "Additionally, the performers in pornography usually have bodies that are unrealistic and inconsistent with most people in real life. This can lead to harmful comparisons that negatively affect intimacy and connection in your relationship. For these reasons, avoidance is strongly recommended."}, {"type": "divider"}, {"type": "bold_text", "content": "Trisha"}, {"type": "text", "content": "Jeff has explained the impact clearly: pornography rewires the brain, lowers satisfaction with real intimacy, fuels impossible comparisons, and creates distance instead of closeness. Avoidance is the healthiest path."}, {"type": "text", "content": "I call it the plague of the century, a silent epidemic that invades homes, hearts, and marriages, often before anyone even realizes the depth of the harm."}, {"type": "text", "content": "What many don''t realize is that hidden pornography use registers in the body much like infidelity or other betrayals, it is a form of betrayal trauma. The person you trust most for safety becomes the source of pain. This rupture triggers the same nervous system responses that I shared earlier: hypervigilance, intrusive thoughts, disrupted sleep, emotional waves, rumination, sudden triggers, and a profound loss of felt safety both in the relationship and within yourself."}, {"type": "text", "content": "Many spouses (often wives, but not exclusively) describe the impact in raw, simple terms:"}, {"type": "list", "items": ["\"He/she is choosing fantasy over me. Am I not enough?\"", "Feeling like an outsider in your own marriage -- lonely even when he/she is right there.", "Waves of grief, anger, confusion, and fear for what else might be hidden.", "Triggers that jolt the body without warning.", "Mourning the exclusivity and security you thought was yours."], "ordered": false}, {"type": "text", "content": "These reactions are not overreactions, they are the body''s honest response to a real violation of trust and covenant. Yet hope remains. Many couples face this very wound -- whether from pornography, infidelity, or other betrayals, and emerge with marriages that are more honest, compassionate, and deeply connected than before. Healing is possible through truth, consistent repair, patience, and practical tools."}, {"type": "text", "content": "If you are trapped in this cycle -- feeling shame, secrecy, and a pull that never truly satisfies, know this: you are not defined by your struggle. Freedom is real and attainable. You are worthy of healing and breaking free from the chains that keep you hidden and disconnected. The same grace extended to the hurting spouse is available to you. Reach out -- no judgment, only help and hope."}, {"type": "text", "content": "Whether you are carrying this hurt yourself, or your spouse is struggling and seeking freedom, you are not alone. Your pain is valid. We have access to an incredible resource that has helped thousands break free from pornography, heal betrayal wounds, restore safety, and rediscover intimacy that honors both hearts. If your relationship is struggling, please reach out. You deserve honesty, safety, and love that chooses you fully. We are here with you."}, {"type": "divider"}, {"type": "bold_text", "content": "Jeff"}, {"type": "subheading", "content": "Part 10: The Action Plan -- Weekly Maintenance"}, {"type": "text", "content": "Focus: Consistency."}, {"type": "text", "content": "A relationship is not a destination; it is a garden."}, {"type": "text", "content": "The Weekly \"State of the Union\": 20 minutes to check in. What went well in our week? Where do we need more SPARK?"}, {"type": "text", "content": "The \"Daily Three\": One word of affirmation, one physical touch, one curious question. I recommend a 15 second hug, a 5 second kiss, and LOOK at each other."}, {"type": "text", "content": "The Trigger Plan: Agree that if a \"Betrayal Trigger\" occurs at any of the six levels of intimacy, the active partner pauses immediately and follows the SPARK steps. Remember your roles: show up fully for your spouse, lean in even when it feels uncomfortable, and stay present."}, {"type": "exercise", "title": "Action Plan Questions", "prompt": "Questions to ask each other. Write down your answers and share with each other. Don''t forget to use SPARK steps when discussing your thoughts to be sure you are hearing and understanding each other:", "steps": ["What words, actions or behaviors do you feel enhance your desire to connect with your partner?", "What dream in your life have you yet to share with your partner?", "After we are sexually intimate, what is one thing I could say or do that would help you feel more safe and anchored to ''us?''", "When things are difficult between us, what is one thing about ''us'' that gives you the most hope to keep going?", "Is there anything I can do to help our intimate experiences together be more pleasurable?"]}, {"type": "divider"}, {"type": "bold_text", "content": "Trisha"}, {"type": "subheading", "content": "A Final Note from My Heart to Yours"}, {"type": "text", "content": "As you move through the layers of intimacy, take a deep breath and acknowledge how far you''ve come. Whether you are standing on a beautiful summit of connection or still navigating the heavy smoke of the healing fire, please hear this: your heart is capable of incredible restoration."}, {"type": "text", "content": "I also want to thank Jeff for the wisdom and guidance he has shared. This roadmap is more than a set of tools, it is a way to reclaim the peace that was stolen and build a sanctuary stronger than before."}, {"type": "text", "content": "Jeff and I are proof that betrayal doesn''t have to be the end; it can be the messy middle of a version of \"us\" that has completely transformed who we have become. You are no longer just surviving -- you are actively forging a bond rooted in truth, protected by safety, and celebrated through joy."}, {"type": "text", "content": "My parting guidance is this: be relentlessly kind to yourself and to each other. Connection is not a destination you reach and then stop. It is a garden you tend every single day. Some days you will plant seeds; some days you will simply pull weeds. Both are sacred work."}, {"type": "text", "content": "Hold onto each other and trust the process. Even the smallest step toward emotional safety is a massive victory. You are reclaiming the peace of being fully known and fully loved. There is no obstacle too great to overcome when you do it together."}, {"type": "text", "content": "With love and hope for your continued journey,"}, {"type": "text", "content": "Trisha"}, {"type": "divider"}, {"type": "bold_text", "content": "Jeff"}, {"type": "subheading", "content": "Appendix: Practical Worksheets"}, {"type": "text", "content": "Focus: Tools for the Fridge."}, {"type": "text", "content": "The SPARK Cheat Sheet: A one-page reminder of the See, Pause, Acknowledge, Reconnect, and Kindle steps. The \"Curious Before Furious\" Worksheet: A guide to pausing when you feel the \"fury\" rising. The Yes/No/Maybe Checklist: A safe way to explore sexual boundaries and desires without the pressure of a face-to-face \"interrogation.\""}, {"type": "text", "content": "The first two are on one single sheet of paper and can be placed on the mirror, on the fridge, or anywhere you can remind yourself of these steps until you get them committed to memory and use them consistently. The last page, when used, will help you understand your partners'' preferences. Print two of these, fill yours out, then share with your spouse. Use SPARK to discuss and understand each other more deeply. These tools will help your combined intimacy skyrocket."}, {"type": "subheading", "content": "SPARK Cheat Sheet"}, {"type": "list", "items": ["[S] SEE -- Turn your body toward them. Look into their eyes. Put down all distractions. Goal: \"I am here. You have my full attention.\"", "[P] PAUSE & PROBE -- Breathe. Ask: \"What felt hardest about that?\" or \"What did you need in that moment?\" Goal: \"I value your perspective over my defense.\"", "[A] ACKNOWLEDGE -- Validate. \"I see why that hurt you,\" or \"It makes sense that you feel unsafe right now.\" Goal: \"Your reality is real and valid to me.\"", "[R] RECONNECT -- Repair. Offer a sincere apology or a reaffirmation: \"I am in this with you. We are a team.\" Goal: \"The ''We'' is more important than the ''Me.''\"", "[K] KINDLE -- Touch. A long hug, holding hands, or a shared deep breath. Goal: \"Let''s reset our nervous systems together.\""], "ordered": true}, {"type": "divider"}, {"type": "subheading", "content": "The \"Curious Before Furious\" Guide"}, {"type": "text", "content": "Goal: To prevent the \"Amygdala Hijack\" (where your brain reacts with anger before thinking). Use this when you feel the \"fury\" rising."}, {"type": "bold_text", "content": "The 4-Step Pause"}, {"type": "list", "items": ["Notice the Body: Is your chest tight? Is your jaw clenched? This is \"Furious\" entering the room.", "The 5-Second Rule: Before you speak, count to five. This allows your prefrontal cortex (the logical brain) to catch up to your emotions.", "The Internal Question: Ask yourself: \"Is it more important to be right or to maintain a healthy relationship?\"", "The Curiosity Pivot: Replace your accusation with a question."], "ordered": true}, {"type": "text", "content": "Transform your language:"}, {"type": "list", "items": ["Instead of: \"You always do this!\" -> Ask: \"What was going on for you at that moment?\"", "Instead of: \"You don''t care!\" -> Ask: \"I''m feeling lonely. Can you help me understand your schedule lately?\"", "Instead of: \"That''s not what happened!\" -> Ask: \"Can you share how you experienced that moment?\""], "ordered": false}, {"type": "divider"}, {"type": "subheading", "content": "The Sexual Connection \"Yes/No/Maybe\" Checklist"}, {"type": "text", "content": "Goal: To build the \"Cherry on Top\" (Sexuality) through clear communication and safety."}, {"type": "text", "content": "Instructions: Fill this out separately. Mark [Y] for Yes, [N] for No, or [M] for Maybe (I''m open to it with more info). Compare lists and focus on the Shared Yes/Maybe items."}, {"type": "bold_text", "content": "I. The Atmosphere (The Accelerators)"}, {"type": "list", "items": ["Soft music/Lighting", "Extended \"Afterglow\" (cuddling/talking)", "Words of Affirmation during intimacy", "Long eye contact (Soul Gazing)"], "ordered": false}, {"type": "bold_text", "content": "II. Physical Connection (Beyond Sex)"}, {"type": "list", "items": ["Full-body massage (no expectation of sex)", "Sitting close/skin-to-skin contact", "Foot rubs/Hand holding", "The 20-second hug before the bedroom"], "ordered": false}, {"type": "bold_text", "content": "III. The Sexual Realm"}, {"type": "list", "items": ["Trying new locations in the house", "Sharing sexual fantasies (verbal)", "Slow, sensual intimacy", "Spontaneous intimacy vs. scheduled \"dates\""], "ordered": false}, {"type": "bold_text", "content": "IV. Emotional Safety (The Brakes)"}, {"type": "list", "items": ["Ability to \"stop\" or \"pause\" at any time without guilt", "Checking in: \"How does this feel for you?\"", "Using the SPARK tool if a trigger occurs", "Discussing sexual needs outside of the bedroom"], "ordered": false}]}');

END $$;
